
CREATE TABLE public.bank_pages (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  slug text UNIQUE NOT NULL,
  title text NOT NULL,
  h1 text NOT NULL,
  meta_title text NOT NULL DEFAULT '',
  meta_description text NOT NULL DEFAULT '',
  keyword text NOT NULL DEFAULT '',
  intro_text text NOT NULL DEFAULT '',
  content text NOT NULL DEFAULT '',
  priority integer NOT NULL DEFAULT 0,
  published boolean NOT NULL DEFAULT true,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

GRANT SELECT ON public.bank_pages TO anon;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.bank_pages TO authenticated;
GRANT ALL ON public.bank_pages TO service_role;

ALTER TABLE public.bank_pages ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Public read published bank_pages"
ON public.bank_pages FOR SELECT
USING (published = true OR public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins manage bank_pages"
ON public.bank_pages FOR ALL
TO authenticated
USING (public.has_role(auth.uid(), 'admin'))
WITH CHECK (public.has_role(auth.uid(), 'admin'));

CREATE TRIGGER update_bank_pages_updated_at
BEFORE UPDATE ON public.bank_pages
FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

INSERT INTO public.bank_pages (slug, title, h1, meta_title, meta_description, keyword, intro_text, content, priority, published) VALUES
(
  'debetovye',
  'Дебетовые карты иностранных банков',
  'Дебетовые карты иностранных банков для россиян в 2026',
  'Дебетовые карты иностранных банков для россиян 2026 — EraPay',
  'Как россиянину открыть дебетовую карту иностранного банка в 2026: страны СНГ, требования, IBAN, плюсы и минусы по сравнению с виртуальными картами.',
  'дебетовая карта иностранного банка',
  'Настоящая дебетовая карта иностранного банка — это счёт с IBAN на ваше имя в банке за пределами России. Ниже — как это работает в 2026 и чем такой инструмент отличается от виртуальных карт-посредников.',
  '<p>Дебетовая карта иностранного банка — это карта, привязанная к вашему личному счёту в банке за пределами России. У вас появляется полноценный IBAN, к которому можно принимать SWIFT/SEPA-переводы, зарплату от иностранного работодателя или платежи от клиентов. В отличие от виртуальных карт-посредников из основного рейтинга EraPay, здесь именно вы — клиент банка, а не пользователь сервиса, купившего лимиты у эмитента.</p>\n<p>Практически доступные для россиян юрисдикции в 2026 — страны СНГ: Армения, Казахстан, Грузия, Узбекистан, Киргизия. Часть банков открывает счёт нерезиденту при личном визите; некоторые требуют местный ИНН или подтверждение адреса, отдельные — временное или постоянное разрешение на пребывание. Онлайн-открытие «под ключ» из России встречается редко и почти всегда сопровождается дополнительной проверкой источника средств.</p>\n<p>Плюсы такой карты по сравнению с виртуалкой: полноценный банковский счёт и IBAN, поддержка Apple Pay и Google Pay в большинстве случаев, возможность снятия наличных в банкоматах по всему миру, более высокие и стабильные лимиты, отдельная кредитная история в этой юрисдикции. Карту принимают везде, где работает платёжная система (Visa, Mastercard, местные схемы), а не только в интернет-магазинах.</p>\n<p>Минусы тоже существенные. Оформление занимает от нескольких дней до нескольких недель и, как правило, требует личного визита. Обслуживание обычно дороже виртуалки: годовая плата за карту, комиссия за неактивность, конвертация по банковскому курсу. Появляются налоговые обязательства — российский резидент обязан уведомлять ФНС об открытии счёта за рубежом и подавать отчёт о движении средств. Наконец, банк может закрыть счёт при подозрительной активности или изменении политики по нерезидентам.</p>\n<p>Дебетовая карта иностранного банка подходит тем, кто регулярно живёт или работает за рубежом, получает валютный доход или ведёт бизнес с зарубежными контрагентами. Для разовых онлайн-покупок и подписок такой инструмент избыточен — быстрее и дешевле оформить виртуальную карту из <a href="/#rating">рейтинга EraPay</a>.</p>',
  30,
  true
),
(
  'kreditnye',
  'Кредитные карты иностранных банков',
  'Кредитные карты иностранных банков: доступны ли россиянам в 2026',
  'Кредитная карта за рубежом для россиян в 2026 — EraPay',
  'Реально ли россиянину получить кредитную карту иностранного банка в 2026: требования, ограничения, риски и разумные альтернативы.',
  'кредитная карта за рубежом для россиян',
  'Кредитная карта иностранного банка — это возобновляемый кредитный лимит, привязанный к вашей платёжеспособности и кредитной истории в этой стране. Для россиянина в 2026 это самый сложный из зарубежных карточных продуктов.',
  '<p>Кредитная карта отличается от дебетовой тем, что банк выдаёт вам возобновляемый кредитный лимит и опирается на вашу платёжеспособность. Для одобрения такой карты банку нужен понятный источник дохода в местной юрисдикции, подтверждённая налоговая история и, как правило, статус резидента. У большинства банков СНГ формальное требование — активная резидентура или ВНЖ, у банков ЕС — постоянный вид на жительство и легальный доход в стране.</p>\n<p>Без резидентства кредитная карта нерезиденту почти нигде не выдаётся: банк не может юридически оценить риск и не имеет инструментов взыскания задолженности. Отдельные банки в Армении, Казахстане и Грузии готовы рассмотреть кредитку клиенту с депозитом-обеспечением — по сути, это secured card: вы кладёте сумму на депозит и получаете кредитный лимит примерно в её размере. Такая карта помогает строить местную кредитную историю, но экономически близка к дебетовой.</p>\n<p>Риски у кредитной карты выше, чем у дебетовой. Ставки в странах СНГ высокие, льготный период короче российского, штрафы за просрочку жёсткие. При закрытии счёта банк вправе досрочно потребовать погашения долга, а взыскание идёт по местному законодательству. Отдельная тема — валютный риск: платежи в лари или тенге при рублёвом доходе делают задолженность непредсказуемой.</p>\n<p>Российский резидент обязан уведомить ФНС об открытии кредитного счёта за рубежом и включать движение средств в ежегодный отчёт. Использование карты для операций, не разрешённых валютным законодательством, ведёт к штрафам вне зависимости от того, в каком банке она выпущена.</p>\n<p>Разумная альтернатива для большинства сценариев — виртуальная карта из <a href="/#rating">рейтинга EraPay</a>, оформленная под конкретную задачу: подписки, реклама, покупки в иностранных магазинах. Она не заменяет кредитный лимит, но снимает 90% практических проблем «карты за рубежом» без резидентства, ВНЖ и обеспечительного депозита.</p>',
  20,
  true
),
(
  's-keshbekom',
  'Карты иностранных банков с кэшбэком',
  'Карты иностранных банков с кэшбэком: обзор 2026',
  'Зарубежные карты с кэшбэком в 2026 — обзор EraPay',
  'Как устроен кэшбэк на картах иностранных банков в 2026, на какие категории он начисляется и стоит ли ради этого открывать зарубежный счёт.',
  'зарубежная карта с кэшбэком',
  'Кэшбэк на карте иностранного банка работает не так, как в российских банках. Ниже — на что реально начисляется вознаграждение, какие условия скрыты за красивыми процентами и когда игра стоит свеч.',
  '<p>Кэшбэк — это возврат части потраченных средств бонусами, милями или деньгами на счёт. В иностранных банках он устроен по одной из трёх моделей: фиксированный процент на все покупки (обычно 0,5–1%), повышенный процент в отдельных категориях (супермаркеты, транспорт, кафе), либо мильная программа лояльности с последующим обменом на билеты и апгрейды.</p>\n<p>У банков СНГ кэшбэк чаще всего рассчитан на местные категории: продукты, кафе, коммунальные платежи внутри страны. Онлайн-покупки в иностранных магазинах, подписки и реклама у большинства программ идут по базовой ставке или вовсе исключены. У европейских и американских банков программы шире, но и требования жёстче: минимальный остаток на счёте, годовая плата за карту, обязательный оборот.</p>\n<p>Прежде чем оценивать кэшбэк, посчитайте полную стоимость владения. Годовое обслуживание премиальной карты может составлять эквивалент 100–500 долларов; на этот платёж нужно «отбить» кэшбэк оборотом. Отдельно — конвертация: если карта в местной валюте, а тратите вы в долларах или евро, банк удержит спред 1–2%, что съедает базовый кэшбэк почти полностью.</p>\n<p>Отдельно стоит смотреть, в чём выплачивается вознаграждение. Мили и бонусы конкретной сети привязаны к её маршрутам и часто «сгорают» через год-два. Деньгами кэшбэк начисляют реже; иногда бонусы можно потратить только внутри экосистемы банка. Проверяйте не только процент, но и то, во что он превращается на практике.</p>\n<p>Для россиянина, у которого нет резидентства, оформлять зарубежную карту исключительно ради кэшбэка редко имеет смысл: годовое обслуживание, налоговая отчётность и валютные риски съедают выгоду. Если задача — вернуть часть трат на онлайн-покупки, реклама или подписки, посмотрите виртуальные карты в <a href="/#rating">рейтинге EraPay</a>: часть сервисов даёт возврат комиссии или бонусные лимиты без открытия банковского счёта за рубежом.</p>',
  10,
  true
);
